using Microsoft.EntityFrameworkCore;

class SyncJob
{
    // Cosmos provider in EF Core 9 no longer supports sync I/O;
    // ToList() and SaveChanges() throw at runtime. Use async equivalents.
    async Task RunAsync(BlogContext context)
    {
        var blogs = await context.Blogs.ToListAsync();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }
        await context.SaveChangesAsync();
    }
}

